section.code:
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://faion.net/schemas/java-spring-boot-patterns.json",
  "type": "object",
  "required": ["spring_boot_version", "base_entity", "uses_record_dtos", "uses_mapstruct", "service_readonly_default", "search_strategy", "uses_problemdetail_advice", "actuator_enabled"],
  "properties": {
    "spring_boot_version": {"type": "string", "pattern": "^3\\."},
    "base_entity": {
      "type": "object",
      "required": ["pk_type", "has_audit", "has_version"],
      "properties": {
        "pk_type": {"const": "UUID"},
        "has_audit": {"type": "boolean", "const": true},
        "has_version": {"type": "boolean", "const": true}
      }
    },
    "uses_record_dtos": {"type": "boolean", "const": true},
    "uses_mapstruct": {"type": "boolean", "const": true},
    "service_readonly_default": {"type": "boolean", "const": true},
    "search_strategy": {"const": "JpaSpecificationExecutor"},
    "uses_problemdetail_advice": {"type": "boolean", "const": true},
    "actuator_enabled": {"type": "boolean", "const": true},
    "forbidden_patterns_found": {"type": "array", "items": {"type": "string"}, "maxItems": 0}
  }
}
